348	// ValidateIgnition wraps the underlying Ignition V2/V3 validation, but explicitly supports
349	// a completely empty Ignition config as valid.  This is because we
350	// want to allow MachineConfig objects which just have e.g. KernelArguments
351	// set, but no Ignition config.
352	// Returns nil if the config is valid (per above) or an error containing a Report otherwise.
353	func ValidateIgnition(ignconfig interface{}) error {
354		switch cfg := ignconfig.(type) {
355		case ign2types.Config:
356			if reflect.DeepEqual(ign2types.Config{}, cfg) {
357				return nil
358			}
359			if report := validate2.ValidateWithoutSource(reflect.ValueOf(cfg)); report.IsFatal() {
360				return fmt.Errorf("invalid ignition V2 config found: %v", report)
361			}
362			return validateIgn2FileModes(cfg)
363		case ign3types.Config:
364			if reflect.DeepEqual(ign3types.Config{}, cfg) {
365				return nil
366			}
367			if report := validate3.ValidateWithContext(cfg, nil); report.IsFatal() {
368				return fmt.Errorf("invalid ignition V3 config found: %v", report)
369			}
370			return validateIgn3FileModes(cfg)
371		default:
372			return fmt.Errorf("unrecognized ignition type")
373		}
374	}
