400	// DecodeIgnitionFileContents returns uncompressed, decoded inline file contents.
401	// This function does not handle remote resources; it assumes they have already
402	// been fetched.
403	func DecodeIgnitionFileContents(source, compression *string) ([]byte, error) {
404		var contentsBytes []byte
405	
406		// To allow writing of "empty" files we'll allow source to be nil
407		if source != nil {
408			source, err := dataurl.DecodeString(*source)
409			if err != nil {
410				return []byte{}, fmt.Errorf("could not decode file content string: %w", err)
411			}
412			if compression != nil {
413				switch *compression {
414				case "":
415					contentsBytes = source.Data
416				case "gzip":
417					reader, err := gzip.NewReader(bytes.NewReader(source.Data))
418					if err != nil {
419						return []byte{}, fmt.Errorf("could not create gzip reader: %w", err)
420					}
421					defer reader.Close()
422					contentsBytes, err = io.ReadAll(reader)
423					if err != nil {
424						return []byte{}, fmt.Errorf("failed decompressing: %w", err)
425					}
426				default:
427					return []byte{}, fmt.Errorf("unsupported compression type %q", *compression)
428				}
429			} else {
430				contentsBytes = source.Data
431			}
432		}
433		return contentsBytes, nil
434	}
